"""OAuth2 Data Models

Defines models for OAuth2 clients, authorization codes, and token storage.
"""

from datetime import datetime
from typing import Optional, Dict, Any, List


class OAuthClient:
    """Represents a registered OAuth2 client application."""

    _clients: Dict[str, 'OAuthClient'] = {}

    def __init__(self, client_id: str, client_secret: str, redirect_uris: List[str], allowed_scopes: List[str]):
        self.client_id = client_id
        self.client_secret = client_secret
        self.redirect_uris = redirect_uris
        self.allowed_scopes = allowed_scopes

    @classmethod
    def lookup(cls, client_id: str) -> Optional['OAuthClient']:
        """Look up a registered client by ID."""
        return cls._clients.get(client_id)

    @classmethod
    def register(cls, client: 'OAuthClient') -> None:
        cls._clients[client.client_id] = client


class TokenStore:
    """Handles persistence of authorization codes and tokens."""

    @staticmethod
    def save_auth_code(db, code_data: Dict[str, Any]) -> None:
        """Persist an authorization code and its bound parameters."""
        db.execute(
            'INSERT INTO auth_codes (code, client_id, redirect_uri, scope, user_id, expires_at) '
            'VALUES (?, ?, ?, ?, ?, ?)',
            (code_data['code'], code_data['client_id'], code_data['redirect_uri'],
             code_data['scope'], code_data['user_id'], code_data['expires_at'].isoformat())
        )
        db.commit()

    @staticmethod
    def get_auth_code(db, code: str) -> Optional[Dict[str, Any]]:
        """Retrieve a stored authorization code."""
        row = db.execute('SELECT * FROM auth_codes WHERE code = ? AND consumed = 0', (code,)).fetchone()
        if row:
            return dict(row)
        return None

    @staticmethod
    def consume_auth_code(db, code: str) -> None:
        """Mark an authorization code as consumed (single-use)."""
        db.execute('UPDATE auth_codes SET consumed = 1 WHERE code = ?', (code,))
        db.commit()

    @staticmethod
    def save_refresh_token(db, token_data: Dict[str, Any]) -> None:
        """Persist a refresh token."""
        db.execute(
            'INSERT INTO refresh_tokens (token, client_id, user_id, scope, expires_at) '
            'VALUES (?, ?, ?, ?, ?)',
            (token_data['token'], token_data['client_id'], token_data['user_id'],
             token_data['scope'], token_data['expires_at'].isoformat())
        )
        db.commit()

    @staticmethod
    def revoke_refresh_token(db, token: str) -> bool:
        """Revoke a refresh token by marking it as revoked."""
        result = db.execute('UPDATE refresh_tokens SET revoked = 1 WHERE token = ?', (token,))
        db.commit()
        return result.rowcount > 0

